import * as THREE from 'three';
import { CONFIG } from '../config';
import { makeAABB, type AABB } from '../systems/CollisionSystem';
import { buildRocketMesh, type RocketMesh } from './rocketSprite';

export type BulletOwner = 'player' | 'enemy';

const PLAYER_COLOR = { color: 0x66ffcc, emissive: 0x0e5c45 };
const ENEMY_COLOR = { color: 0xff5577, emissive: 0x661122 };

export class Bullet {
  readonly mesh: THREE.Group;
  private readonly rocket: RocketMesh;
  owner: BulletOwner = 'player';
  active = false;
  // Lateral (X/Y) velocity used by homing enemy projectiles.
  private vx = 0;
  private vy = 0;

  constructor() {
    this.rocket = buildRocketMesh();
    this.mesh = this.rocket.group;
    this.mesh.visible = false;
  }

  spawn(
    owner: BulletOwner,
    position: { x: number; y: number; z: number },
  ): void {
    this.owner = owner;
    this.active = true;
    this.vx = 0;
    this.vy = 0;
    this.mesh.visible = true;
    this.mesh.position.set(position.x, position.y, position.z);
    // Player rockets fly +Z (nose forward = default); enemy rockets fly -Z, so
    // rotate them 180° about Y to point their nose toward the player.
    this.mesh.rotation.y = owner === 'enemy' ? Math.PI : 0;
    const c = owner === 'player' ? PLAYER_COLOR : ENEMY_COLOR;
    this.rocket.setColor(c.color, c.emissive);
  }

  deactivate(): void {
    this.active = false;
    this.mesh.visible = false;
  }

  /**
   * Advances the bullet. Player bullets fly straight along +Z. Enemy bullets
   * fly along -Z and, when homing is enabled, steer their lateral (X/Y)
   * velocity toward the given `target` position. `homing` overrides the static
   * config so callers (e.g. per-level difficulty) can tune tracking strength.
   */
  update(
    dt: number,
    target?: { x: number; y: number },
    homing: number = CONFIG.bullet.enemyHoming,
  ): void {
    if (!this.active) return;

    this.rocket.tick(dt);

    if (this.owner === 'player') {
      this.mesh.position.z += CONFIG.bullet.playerSpeed * dt;
      return;
    }

    // Enemy bullet: constant forward motion toward the player.
    this.mesh.position.z -= CONFIG.bullet.enemySpeed * dt;

    if (target && homing > 0) {
      // Steer lateral velocity toward the target's X/Y.
      const dx = target.x - this.mesh.position.x;
      const dy = target.y - this.mesh.position.y;
      const accel = homing;
      this.vx += dx * accel * dt;
      this.vy += dy * accel * dt;

      // Clamp lateral speed so homing stays fair/configurable.
      const max = CONFIG.bullet.enemyHomingMaxSpeed;
      const speed = Math.hypot(this.vx, this.vy);
      if (speed > max) {
        const k = max / speed;
        this.vx *= k;
        this.vy *= k;
      }
    }

    this.mesh.position.x += this.vx * dt;
    this.mesh.position.y += this.vy * dt;
  }

  get aabb(): AABB {
    return makeAABB(this.mesh.position, CONFIG.bullet.size);
  }
}

/** Fixed-size pool of bullets shared by the player and enemies. */
export class BulletPool {
  readonly bullets: Bullet[] = [];
  /** Homing strength applied to enemy projectiles; set per level. */
  enemyHoming: number = CONFIG.bullet.enemyHoming;

  constructor(scene: THREE.Scene) {
    for (let i = 0; i < CONFIG.bullet.maxActive; i++) {
      const bullet = new Bullet();
      scene.add(bullet.mesh);
      this.bullets.push(bullet);
    }
  }

  fire(owner: BulletOwner, position: { x: number; y: number; z: number }): void {
    const bullet = this.bullets.find((b) => !b.active);
    if (bullet) bullet.spawn(owner, position);
  }

  update(dt: number, target?: { x: number; y: number }): void {
    for (const bullet of this.bullets) {
      bullet.update(dt, target, this.enemyHoming);
      if (!bullet.active) continue;
      const z = bullet.mesh.position.z;
      // Despawn once a bullet flies past either end of the battlefield.
      if (z > CONFIG.enemies.startZ + 4 || z < -20) {
        bullet.deactivate();
      }
    }
  }

  reset(): void {
    this.enemyHoming = CONFIG.bullet.enemyHoming;
    for (const bullet of this.bullets) bullet.deactivate();
  }

  /** Number of active bullets belonging to the given owner. */
  activeCount(owner: BulletOwner): number {
    let n = 0;
    for (const bullet of this.bullets) {
      if (bullet.active && bullet.owner === owner) n++;
    }
    return n;
  }
}
