import { CONFIG } from '../config';
import { GameState } from '../state/GameState';
import { LeaderboardService } from '../services/LeaderboardService';
import { LeaderboardDisplay } from './LeaderboardDisplay';

/**
 * DOM overlay for score/lives plus the start and game-over screens.
 * Calls `onStart` when the player presses the start/restart button.
 */
export class HUD {
  private readonly hud: HTMLDivElement;
  private readonly scoreEl: HTMLSpanElement;
  private readonly livesEl: HTMLSpanElement;
  private readonly levelEl: HTMLSpanElement;
  private readonly overlay: HTMLDivElement;
  private readonly title: HTMLHeadingElement;
  private readonly message: HTMLParagraphElement;
  private readonly button: HTMLButtonElement;
  private readonly retryButton: HTMLButtonElement;
  private readonly buttonRow: HTMLDivElement;
  private readonly leaderboardDisplay: LeaderboardDisplay;

  constructor(
    private readonly root: HTMLElement,
    private readonly onStart: () => void,
    leaderboard: LeaderboardService,
    private readonly onRetry: () => void = onStart,
  ) {
    this.hud = document.createElement('div');
    this.hud.id = 'hud';
    this.scoreEl = document.createElement('span');
    this.livesEl = document.createElement('span');
    this.levelEl = document.createElement('span');
    this.hud.append(this.scoreEl, this.levelEl, this.livesEl);

    this.overlay = document.createElement('div');
    this.overlay.id = 'overlay';
    this.title = document.createElement('h1');
    this.message = document.createElement('p');
    const controls = document.createElement('p');
    controls.className = 'controls';
    controls.textContent =
      'MOVE: Arrow Keys / WASD   ·   SHOOT: Space';

    this.buttonRow = document.createElement('div');
    this.buttonRow.className = 'button-row';
    this.button = document.createElement('button');
    this.button.addEventListener('click', () => this.onStart());
    this.retryButton = document.createElement('button');
    this.retryButton.className = 'retry';
    this.retryButton.textContent = 'RETRY LEVEL';
    this.retryButton.addEventListener('click', () => this.onRetry());
    this.buttonRow.append(this.button, this.retryButton);

    const leaderboardContainer = document.createElement('div');
    this.leaderboardDisplay = new LeaderboardDisplay(leaderboardContainer, leaderboard);

    this.overlay.append(this.title, this.message, controls, this.buttonRow, leaderboardContainer);

    this.root.append(this.hud, this.overlay);
    this.showStart();
  }

  update(state: GameState): void {
    this.scoreEl.textContent = `SCORE ${state.score.toString().padStart(6, '0')}`;
    this.levelEl.textContent = `LEVEL ${state.level}`;
    this.livesEl.textContent = `LIVES ${'♥'.repeat(state.lives) || '—'}`;
  }

  showStart(): void {
    this.title.textContent = 'ISO INVADERS';
    this.message.textContent =
      'Defend against the advancing 3D invader fleet. Move on two axes and blast them before they reach you.';
    this.button.textContent = 'START';
    this.retryButton.classList.add('hidden');
    this.leaderboardDisplay.refresh();
    this.overlay.classList.remove('hidden');
  }

  showGameOver(state: GameState): void {
    this.title.textContent = 'GAME OVER';
    this.message.textContent = `The invaders broke through on level ${state.level}. Final score: ${state.score}.`;
    this.button.textContent = 'PLAY AGAIN';
    this.retryButton.textContent = `RETRY LEVEL ${state.level}`;
    this.retryButton.classList.remove('hidden');
    this.leaderboardDisplay.refresh();
    this.overlay.classList.remove('hidden');
  }

  hideOverlay(): void {
    this.overlay.classList.add('hidden');
  }
}

export const FULL_FLEET = CONFIG.enemies.cols * CONFIG.enemies.rows;
