/**
 * Brief "LEVEL N" banner shown when a new level begins, then auto-dismissed so
 * play can resume. Follows the existing DOM-overlay UI pattern.
 */
export class LevelBanner {
  private readonly el: HTMLDivElement;
  private timer: ReturnType<typeof setTimeout> | null = null;
  private visible = false;

  constructor(root: HTMLElement) {
    this.el = document.createElement('div');
    this.el.id = 'level-banner';
    this.el.classList.add('hidden');
    root.append(this.el);
  }

  /** Display "LEVEL N" and auto-hide after `durationMs` (default short). */
  show(level: number, durationMs = 1600): void {
    if (this.timer !== null) {
      clearTimeout(this.timer);
      this.timer = null;
    }
    this.el.textContent = `LEVEL ${level}`;
    this.el.classList.remove('hidden');
    this.visible = true;
    this.timer = setTimeout(() => this.hide(), durationMs);
  }

  /** Hide the banner immediately. */
  hide(): void {
    if (this.timer !== null) {
      clearTimeout(this.timer);
      this.timer = null;
    }
    this.el.classList.add('hidden');
    this.visible = false;
  }

  get isVisible(): boolean {
    return this.visible;
  }
}
