/**
 * Minimal Web Audio synthesizer for arcade SFX. No audio files required.
 * The AudioContext is created lazily on first sound (after a user gesture)
 * to comply with browser autoplay policies.
 */
export class AudioManager {
  private ctx: AudioContext | null = null;

  private ensure(): AudioContext {
    if (!this.ctx) {
      this.ctx = new AudioContext();
    }
    if (this.ctx.state === 'suspended') {
      void this.ctx.resume();
    }
    return this.ctx;
  }

  private tone(
    type: OscillatorType,
    startFreq: number,
    endFreq: number,
    duration: number,
    volume = 0.2,
  ): void {
    const ctx = this.ensure();
    const now = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = type;
    osc.frequency.setValueAtTime(startFreq, now);
    osc.frequency.exponentialRampToValueAtTime(
      Math.max(endFreq, 1),
      now + duration,
    );

    gain.gain.setValueAtTime(volume, now);
    gain.gain.exponentialRampToValueAtTime(0.0001, now + duration);

    osc.connect(gain).connect(ctx.destination);
    osc.start(now);
    osc.stop(now + duration);
  }

  shoot(): void {
    this.tone('square', 880, 220, 0.12, 0.12);
  }

  explosion(): void {
    this.tone('sawtooth', 320, 40, 0.3, 0.2);
  }

  playerHit(): void {
    this.tone('triangle', 200, 60, 0.4, 0.25);
  }

  gameOver(): void {
    this.tone('sawtooth', 400, 30, 0.9, 0.25);
  }
}
