import * as THREE from 'three';
import { CONFIG } from '../config';

interface Particle {
  position: THREE.Vector3;
  velocity: THREE.Vector3;
  spin: THREE.Vector3;
  rotation: THREE.Euler;
}

/**
 * A single reusable explosion burst: a cloud of small cube particles that fly
 * outward from a point, slow down (drag), fall (gravity), spin, and fade out
 * over a fixed lifetime. Rendered as one InstancedMesh for efficiency.
 */
class Burst {
  readonly mesh: THREE.InstancedMesh;
  private readonly particles: Particle[] = [];
  private readonly material: THREE.MeshBasicMaterial;
  private elapsed = 0;
  private live = false;

  private readonly _m = new THREE.Matrix4();
  private readonly _q = new THREE.Quaternion();
  private readonly _s = new THREE.Vector3(1, 1, 1);

  constructor() {
    const cfg = CONFIG.explosion;
    const geometry = new THREE.BoxGeometry(
      cfg.particleSize,
      cfg.particleSize,
      cfg.particleSize,
    );
    this.material = new THREE.MeshBasicMaterial({
      color: 0xffffff,
      transparent: true,
      opacity: 1,
      depthWrite: false,
      blending: THREE.AdditiveBlending,
    });
    this.mesh = new THREE.InstancedMesh(geometry, this.material, cfg.particles);
    this.mesh.visible = false;
    this.mesh.frustumCulled = false;
    for (let i = 0; i < cfg.particles; i++) {
      this.particles.push({
        position: new THREE.Vector3(),
        velocity: new THREE.Vector3(),
        spin: new THREE.Vector3(),
        rotation: new THREE.Euler(),
      });
    }
  }

  get isLive(): boolean {
    return this.live;
  }

  /** Immediately stops and hides this burst. */
  stop(): void {
    this.live = false;
    this.mesh.visible = false;
  }

  ignite(origin: { x: number; y: number; z: number }): void {
    const cfg = CONFIG.explosion;
    this.elapsed = 0;
    this.live = true;
    this.mesh.visible = true;

    const palette = cfg.colors;
    const color = new THREE.Color(
      palette[Math.floor(Math.random() * palette.length)],
    );
    this.material.color.copy(color);
    this.material.opacity = 1;

    for (const p of this.particles) {
      p.position.set(origin.x, origin.y, origin.z);
      // Random direction on a sphere.
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const speed = cfg.minSpeed + Math.random() * (cfg.maxSpeed - cfg.minSpeed);
      const sinPhi = Math.sin(phi);
      p.velocity.set(
        Math.cos(theta) * sinPhi * speed,
        Math.cos(phi) * speed,
        Math.sin(theta) * sinPhi * speed,
      );
      p.spin.set(
        (Math.random() - 0.5) * 12,
        (Math.random() - 0.5) * 12,
        (Math.random() - 0.5) * 12,
      );
      p.rotation.set(0, 0, 0);
    }
    this.writeMatrices();
  }

  update(dt: number): void {
    if (!this.live) return;
    const cfg = CONFIG.explosion;
    this.elapsed += dt;

    if (this.elapsed >= cfg.duration) {
      this.live = false;
      this.mesh.visible = false;
      return;
    }

    const dragFactor = Math.max(0, 1 - cfg.drag * dt);
    for (const p of this.particles) {
      p.velocity.multiplyScalar(dragFactor);
      p.velocity.y -= cfg.gravity * dt;
      p.position.addScaledVector(p.velocity, dt);
      p.rotation.x += p.spin.x * dt;
      p.rotation.y += p.spin.y * dt;
      p.rotation.z += p.spin.z * dt;
    }
    this.writeMatrices();

    const t = this.elapsed / cfg.duration;
    this.material.opacity = 1 - t * t; // ease-out fade
  }

  private writeMatrices(): void {
    for (let i = 0; i < this.particles.length; i++) {
      const p = this.particles[i];
      this._q.setFromEuler(p.rotation);
      this._m.compose(p.position, this._q, this._s);
      this.mesh.setMatrixAt(i, this._m);
    }
    this.mesh.instanceMatrix.needsUpdate = true;
  }
}

/**
 * Pool of explosion bursts. Call `spawn()` at a hit position to play one, and
 * `update(dt)` each frame to advance all live bursts.
 */
export class ExplosionSystem {
  readonly group = new THREE.Group();
  private readonly bursts: Burst[] = [];

  constructor() {
    for (let i = 0; i < CONFIG.explosion.maxBursts; i++) {
      const burst = new Burst();
      this.bursts.push(burst);
      this.group.add(burst.mesh);
    }
  }

  /** Number of bursts currently animating. */
  get activeCount(): number {
    return this.bursts.reduce((n, b) => n + (b.isLive ? 1 : 0), 0);
  }

  /** Plays an explosion at the given world position (reuses a free burst). */
  spawn(origin: { x: number; y: number; z: number }): void {
    const free = this.bursts.find((b) => !b.isLive) ?? this.bursts[0];
    free.ignite(origin);
  }

  update(dt: number): void {
    for (const b of this.bursts) b.update(dt);
  }

  /** Stops and hides every burst (used on game reset). */
  reset(): void {
    for (const b of this.bursts) b.stop();
  }
}
