import type { UpgradeType } from '../state/GameState';

interface UpgradeOption {
  type: UpgradeType;
  title: string;
  icon: string;
  describe: (state: { extraShots: number; speedPicks: number }) => string;
}

/**
 * Inline SVG icons for each advantage, drawn with `currentColor` so they pick
 * up the card's neon accent and glow. 64x64 viewBox, simple arcade-style shapes.
 */
const ICON_MULTISHOT = `
<svg viewBox="0 0 64 64" fill="none" aria-hidden="true">
  <g stroke="currentColor" stroke-width="4" stroke-linecap="round" stroke-linejoin="round">
    <path d="M16 50 V22 l-6 6 M16 22 l6 6" fill="none"/>
    <path d="M32 50 V14 l-6 6 M32 14 l6 6" fill="none"/>
    <path d="M48 50 V22 l-6 6 M48 22 l6 6" fill="none"/>
  </g>
</svg>`;

const ICON_SPEED = `
<svg viewBox="0 0 64 64" fill="none" aria-hidden="true">
  <g fill="currentColor">
    <path d="M30 8 L14 36 H28 L24 56 L50 26 H34 L40 8 Z"/>
  </g>
</svg>`;

const ICON_LIFE = `
<svg viewBox="0 0 64 64" fill="none" aria-hidden="true">
  <path d="M32 54 C12 40 8 26 16 18 C22 12 30 14 32 22 C34 14 42 12 48 18 C56 26 52 40 32 54 Z"
        fill="currentColor"/>
</svg>`;

const OPTIONS: UpgradeOption[] = [
  {
    type: 'multishot',
    title: 'MULTI-SHOT',
    icon: ICON_MULTISHOT,
    describe: (s) =>
      `Fire ${2 + s.extraShots} parallel projectiles with every shot.`,
  },
  {
    type: 'speed',
    title: 'SHIP SPEED',
    icon: ICON_SPEED,
    describe: () => 'Boost your ship\u2019s movement speed.',
  },
  {
    type: 'life',
    title: 'EXTRA LIFE',
    icon: ICON_LIFE,
    describe: () => 'Gain one additional life.',
  },
];

/**
 * Between-levels popup that lets the player choose one of three stacking
 * advantages. Calls `onChoose` with the selected upgrade type, then hides.
 * Follows the existing DOM-overlay UI pattern.
 */
export class UpgradeMenu {
  private readonly el: HTMLDivElement;
  private onChoose: ((type: UpgradeType) => void) | null = null;

  constructor(root: HTMLElement) {
    this.el = document.createElement('div');
    this.el.id = 'upgrade-overlay';
    this.el.classList.add('hidden');
    root.append(this.el);
  }

  /** Show the menu for the given level; `state` drives dynamic descriptions. */
  show(
    level: number,
    state: { extraShots: number; speedPicks: number },
    onChoose: (type: UpgradeType) => void,
  ): void {
    this.onChoose = onChoose;
    this.el.replaceChildren();

    const heading = document.createElement('h2');
    heading.textContent = `LEVEL ${level} \u2013 CHOOSE AN ADVANTAGE`;
    this.el.append(heading);

    const cards = document.createElement('div');
    cards.className = 'upgrade-cards';
    for (const option of OPTIONS) {
      const card = document.createElement('button');
      card.className = 'upgrade-card';
      card.dataset.upgrade = option.type;

      const icon = document.createElement('span');
      icon.className = 'upgrade-icon';
      icon.innerHTML = option.icon;

      const t = document.createElement('span');
      t.className = 'upgrade-title';
      t.textContent = option.title;

      const d = document.createElement('span');
      d.className = 'upgrade-desc';
      d.textContent = option.describe(state);

      card.append(icon, t, d);
      card.addEventListener('click', () => this.pick(option.type));
      cards.append(card);
    }
    this.el.append(cards);
    this.el.classList.remove('hidden');
  }

  private pick(type: UpgradeType): void {
    const cb = this.onChoose;
    this.onChoose = null;
    this.hide();
    cb?.(type);
  }

  hide(): void {
    this.el.classList.add('hidden');
  }

  get isVisible(): boolean {
    return !this.el.classList.contains('hidden');
  }
}
