import type { Vec3Size } from '../config';

/** Axis-aligned bounding box defined by a center position and half-extents. */
export interface AABB {
  x: number;
  y: number;
  z: number;
  hx: number;
  hy: number;
  hz: number;
}

export function makeAABB(
  position: { x: number; y: number; z: number },
  size: Vec3Size,
): AABB {
  return {
    x: position.x,
    y: position.y,
    z: position.z,
    hx: size.x / 2,
    hy: size.y / 2,
    hz: size.z / 2,
  };
}

export function intersects(a: AABB, b: AABB): boolean {
  return (
    Math.abs(a.x - b.x) <= a.hx + b.hx &&
    Math.abs(a.y - b.y) <= a.hy + b.hy &&
    Math.abs(a.z - b.z) <= a.hz + b.hz
  );
}
