import { CONFIG } from '../config';

export type GameStatus =
  | 'idle'
  | 'playing'
  | 'choosing_upgrade'
  | 'entering_initials'
  | 'over';

/** The three stacking advantages the player can choose between levels. */
export type UpgradeType = 'multishot' | 'speed' | 'life';

export class GameState {
  score = 0;
  lives: number = CONFIG.player.startLives;
  status: GameStatus = 'idle';
  level = 1;
  /** Level a new game begins at; normally 1, overridable for debug/cheats. */
  startLevel = 1;

  /** Number of EXTRA parallel shots beyond the first (0 = single shot). */
  extraShots = 0;
  /** Number of "increase ship speed" picks taken (each adds a speed step). */
  speedPicks = 0;

  reset(): void {
    this.score = 0;
    this.lives = CONFIG.player.startLives;
    this.status = 'playing';
    this.level = Math.max(1, Math.floor(this.startLevel));
    this.extraShots = 0;
    this.speedPicks = 0;
  }

  /**
   * Retry the level the player just died on: score resets to 0 and lives refill,
   * but the current `level` is kept (unlike {@link reset}, which returns to the
   * configured start level).
   */
  retryLevel(): void {
    this.score = 0;
    this.lives = CONFIG.player.startLives;
    this.status = 'playing';
  }

  /** Advance to the next level, keeping score and lives. */
  advanceLevel(): void {
    this.level += 1;
  }

  /** Add the scaling level-clear bonus (bonusBase × level); return the amount. */
  awardLevelClearBonus(): number {
    const bonus = CONFIG.levels.bonusBase * this.level;
    this.score += bonus;
    return bonus;
  }

  /** Total parallel projectiles fired per shot (1 + chosen multishot picks). */
  get shotCount(): number {
    return 1 + this.extraShots;
  }

  /** Current ship speed including all chosen speed upgrades. */
  get shipSpeed(): number {
    return CONFIG.player.speed + this.speedPicks * CONFIG.player.upgrades.speedPerPick;
  }

  /** Apply one chosen advantage. Multishot/speed stack; life grants +1 life. */
  applyUpgrade(type: UpgradeType): void {
    switch (type) {
      case 'multishot':
        this.extraShots += 1;
        break;
      case 'speed':
        this.speedPicks += 1;
        break;
      case 'life':
        this.lives += 1;
        break;
    }
  }

  addScore(points: number): void {
    this.score += points;
  }

  loseLife(): void {
    this.lives = Math.max(0, this.lives - 1);
    if (this.lives === 0) {
      this.status = 'over';
    }
  }

  end(): void {
    this.status = 'over';
  }
}
