import * as Tone from 'tone';
import { Midi } from '@tonejs/midi';
import { CONFIG } from '../config';

/**
 * Resolves a relative asset path (e.g. `music/stage-1.mid`) against Vite's
 * configured base URL so it works both at the site root in dev and under a
 * subpath in production (e.g. GitHub Pages `/iso-invaders/`).
 */
function resolveAssetUrl(path: string): string {
  const base = import.meta.env.BASE_URL ?? '/';
  return `${base.replace(/\/$/, '')}/${path.replace(/^\//, '')}`;
}

/**
 * Plays MIDI files as looping background music, synthesized in the browser via
 * Tone.js. Each MIDI track is rendered with a PolySynth and routed through a
 * shared, configurable effects chain (filter, chorus, delay, distortion,
 * reverb) so the overall feel can be tuned from {@link CONFIG.music}. The whole
 * transport loops until a different song is requested (e.g. on level change).
 *
 * Browsers block audio until a user gesture, so {@link unlock} must be called
 * from within a click/keypress handler before playback will be audible.
 */
export class MusicPlayer {
  private synths: Tone.PolySynth[] = [];
  private parts: Tone.Part[] = [];
  private gain: Tone.Gain | null = null;
  /** Brick-wall limiter on the master bus to prevent clipping/saturation. */
  private limiter: Tone.Limiter | null = null;
  /** Head of the shared effects chain that synths connect into. */
  private chainInput: Tone.ToneAudioNode | null = null;
  /** Effect nodes built once on unlock, disposed when the player stops. */
  private effects: Tone.ToneAudioNode[] = [];
  /** MIDI URL currently loaded/playing, to avoid restarting the same song. */
  private currentUrl: string | null = null;
  /** Token guarding against races when switching songs while one is loading. */
  private loadToken = 0;
  private unlocked = false;
  private readonly cache = new Map<string, Midi>();

  /**
   * Resolves the MIDI URL for a level (1-based), cycling through the playlist.
   */
  songForLevel(level: number): string | null {
    const list: readonly string[] = CONFIG.music.playlist;
    if (!CONFIG.music.enabled || list.length < 1) return null;
    const n = list.length;
    const i = (((Math.max(1, Math.floor(level)) - 1) % n) + n) % n;
    return list[i];
  }

  /**
   * Must be called from a user gesture (e.g. the Start button handler) to lift
   * the browser autoplay restriction. Safe to call repeatedly.
   */
  async unlock(): Promise<void> {
    if (this.unlocked) return;
    await Tone.start();
    this.limiter = new Tone.Limiter(CONFIG.music.limiterThresholdDb).toDestination();
    this.gain = new Tone.Gain(Tone.dbToGain(CONFIG.music.volumeDb)).connect(this.limiter);
    this.buildEffectsChain();
    Tone.getTransport().bpm.value = 120;
    this.unlocked = true;
  }

  /**
   * Builds the post-synth effects chain (filter -> chorus -> distortion ->
   * delay -> reverb -> master gain). Disabled effects are skipped. Synths
   * connect to {@link chainInput}; if everything is disabled they go straight
   * to the master gain.
   */
  private buildEffectsChain(): void {
    // Tear down any previously built chain before rebuilding (idempotent).
    for (const node of this.effects) node.dispose();
    this.effects = [];

    const fx = CONFIG.music.effects;
    const nodes: Tone.ToneAudioNode[] = [];

    if (fx.filter.enabled) {
      nodes.push(
        new Tone.Filter({
          frequency: fx.filter.frequency,
          type: fx.filter.type,
          Q: fx.filter.Q,
        }),
      );
    }
    if (fx.chorus.enabled) {
      const chorus = new Tone.Chorus({
        frequency: fx.chorus.frequency,
        delayTime: fx.chorus.delayTime,
        depth: fx.chorus.depth,
        wet: fx.chorus.wet,
      }).start();
      nodes.push(chorus);
    }
    if (fx.distortion.enabled) {
      nodes.push(new Tone.Distortion({ distortion: fx.distortion.amount, wet: fx.distortion.wet }));
    }
    if (fx.delay.enabled) {
      nodes.push(
        new Tone.FeedbackDelay({
          delayTime: fx.delay.delayTime,
          feedback: fx.delay.feedback,
          wet: fx.delay.wet,
        }),
      );
    }
    if (fx.reverb.enabled) {
      nodes.push(
        new Tone.Reverb({
          decay: fx.reverb.decay,
          preDelay: fx.reverb.preDelay,
          wet: fx.reverb.wet,
        }),
      );
    }

    this.effects = nodes;
    if (nodes.length === 0) {
      this.chainInput = this.gain;
      return;
    }
    // Wire effects in series, terminating at the master gain.
    for (let i = 0; i < nodes.length - 1; i++) nodes[i].connect(nodes[i + 1]);
    nodes[nodes.length - 1].connect(this.gain!);
    this.chainInput = nodes[0];
  }

  /** Loads and starts looping the song for the given level. */
  async playForLevel(level: number): Promise<void> {
    const url = this.songForLevel(level);
    if (!url) return;
    await this.play(url);
  }

  /** Loads (if needed) and starts looping the given MIDI URL. */
  async play(url: string): Promise<void> {
    if (!CONFIG.music.enabled) return;
    if (url === this.currentUrl) return; // already playing this song
    await this.unlock();

    const token = ++this.loadToken;
    const midi = await this.load(url);
    // A newer request superseded this one while we were loading/parsing.
    if (token !== this.loadToken) return;

    this.stopParts();
    this.currentUrl = url;
    this.schedule(midi);

    const transport = Tone.getTransport();
    transport.stop();
    transport.position = 0;
    transport.start('+0.05');
  }

  /** Stops playback and tears down the current song's nodes. */
  stop(): void {
    this.loadToken++; // cancel any in-flight load
    this.currentUrl = null;
    const transport = Tone.getTransport();
    transport.stop();
    transport.cancel();
    this.stopParts();
  }

  private async load(url: string): Promise<Midi> {
    const cached = this.cache.get(url);
    if (cached) return cached;
    const midi = await Midi.fromUrl(resolveAssetUrl(url));
    this.cache.set(url, midi);
    return midi;
  }

  private schedule(midi: Midi): void {
    const transport = Tone.getTransport();
    transport.cancel(); // clear any previously scheduled events
    // Loop the whole transport over the song's duration. Add a small tail so
    // release envelopes can decay before the loop restarts (prevents the
    // click/pop at the loop seam where ringing notes would be cut abruptly).
    const tail = CONFIG.music.synth.envelope.release + 0.15;
    transport.loop = true;
    transport.loopStart = 0;
    transport.loopEnd = Math.max(0.1, midi.duration + tail);

    for (const track of midi.tracks) {
      if (track.notes.length === 0) continue;
      const synth = new Tone.PolySynth(Tone.Synth, {
        oscillator: { type: CONFIG.music.synth.oscillator } as Tone.SynthOptions['oscillator'],
        envelope: { ...CONFIG.music.synth.envelope },
      });
      synth.maxPolyphony = CONFIG.music.synth.maxPolyphony;
      synth.connect(this.chainInput ?? this.gain!);
      this.synths.push(synth);

      const part = new Tone.Part((time, note: NoteEvent) => {
        synth.triggerAttackRelease(note.name, note.duration, time, note.velocity);
      }, track.notes.map((n) => ({
        time: n.time,
        name: n.name,
        duration: n.duration,
        velocity: n.velocity,
      } as NoteEvent)));
      part.loop = false; // the transport loops; the part plays once per loop
      part.start(0);
      this.parts.push(part);
    }
  }

  /**
   * Stops and disposes the current song's parts/synths. Voices are released
   * (not hard-cut) and synths are disposed after the release tail so switching
   * songs doesn't produce a click from abruptly silenced audio.
   */
  private stopParts(): void {
    for (const part of this.parts) {
      part.stop();
      part.dispose();
    }
    this.parts = [];

    const synths = this.synths;
    this.synths = [];
    for (const synth of synths) {
      try {
        synth.releaseAll();
      } catch {
        // Some states (already disposed) can't release; ignore.
      }
    }
    const releaseMs = (CONFIG.music.synth.envelope.release + 0.1) * 1000;
    setTimeout(() => {
      for (const synth of synths) synth.dispose();
    }, releaseMs);
  }
}

interface NoteEvent {
  time: number;
  name: string;
  duration: number;
  velocity: number;
}
