const KEYS = new Set([
  'ArrowLeft',
  'ArrowRight',
  'ArrowUp',
  'ArrowDown',
  'KeyA',
  'KeyD',
  'KeyW',
  'KeyS',
  'Space',
]);

/**
 * Tracks the current keyboard state plus optional touch/virtual input. `moveX`/
 * `moveY` combine keyboard direction with an analog joystick vector (touch).
 * `consumeFire` returns true once per Space press / fire tap; `fireHeld` is true
 * while the touch fire button is held (enables auto-fire at the ship cooldown).
 */
export class InputManager {
  private readonly down = new Set<string>();
  private firePressed = false;
  /** Analog movement vector from a virtual joystick, each component in [-1,1]. */
  private analogX = 0;
  private analogY = 0;
  /** True while the touch fire button is held down (continuous fire). */
  private touchFireHeld = false;

  constructor() {
    window.addEventListener('keydown', this.onKeyDown);
    window.addEventListener('keyup', this.onKeyUp);
  }

  private onKeyDown = (e: KeyboardEvent): void => {
    if (!KEYS.has(e.code)) return;
    e.preventDefault();
    if (e.code === 'Space' && !this.down.has('Space')) {
      this.firePressed = true;
    }
    this.down.add(e.code);
  };

  private onKeyUp = (e: KeyboardEvent): void => {
    if (!KEYS.has(e.code)) return;
    e.preventDefault();
    this.down.delete(e.code);
  };

  // --- Touch / virtual control hooks ---------------------------------------

  /** Set the analog joystick vector (components clamped to [-1, 1]). */
  setAnalog(x: number, y: number): void {
    this.analogX = clamp(x, -1, 1);
    this.analogY = clamp(y, -1, 1);
  }

  /** Recenter the joystick (no movement). */
  clearAnalog(): void {
    this.analogX = 0;
    this.analogY = 0;
  }

  /** Register a one-shot fire (touch fire button tap), like a Space press. */
  pressFire(): void {
    this.firePressed = true;
  }

  /** Set whether the touch fire button is currently held (auto-fire). */
  setFireHeld(held: boolean): void {
    this.touchFireHeld = held;
  }

  /** True while continuous fire should occur (touch fire button held). */
  get fireHeld(): boolean {
    return this.touchFireHeld;
  }

  get moveX(): number {
    let x = 0;
    if (this.down.has('ArrowLeft') || this.down.has('KeyA')) x -= 1;
    if (this.down.has('ArrowRight') || this.down.has('KeyD')) x += 1;
    // Analog overrides/augments keyboard; clamp the combined value.
    return clamp(x + this.analogX, -1, 1);
  }

  get moveY(): number {
    let y = 0;
    if (this.down.has('ArrowDown') || this.down.has('KeyS')) y -= 1;
    if (this.down.has('ArrowUp') || this.down.has('KeyW')) y += 1;
    return clamp(y + this.analogY, -1, 1);
  }

  /** Returns true exactly once per Space keypress / fire tap (tap-to-shoot). */
  consumeFire(): boolean {
    if (this.firePressed) {
      this.firePressed = false;
      return true;
    }
    return false;
  }

  dispose(): void {
    window.removeEventListener('keydown', this.onKeyDown);
    window.removeEventListener('keyup', this.onKeyUp);
  }
}

function clamp(v: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, v));
}
