import { LeaderboardService } from '../services/LeaderboardService';

export class LeaderboardDisplay {
  private readonly container: HTMLElement;
  private readonly leaderboard: LeaderboardService;

  constructor(container: HTMLElement, leaderboard: LeaderboardService) {
    this.container = container;
    this.leaderboard = leaderboard;
  }

  refresh(): void {
    this.container.innerHTML = '';

    const wrapper = document.createElement('div');
    wrapper.className = 'leaderboard';

    const heading = document.createElement('h2');
    heading.textContent = 'HIGH SCORES';
    wrapper.appendChild(heading);

    const entries = this.leaderboard.getAll();

    if (entries.length === 0) {
      const placeholder = document.createElement('p');
      placeholder.className = 'placeholder';
      placeholder.textContent = 'No scores yet';
      wrapper.appendChild(placeholder);
    } else {
      const table = document.createElement('table');

      const headerRow = document.createElement('tr');
      headerRow.className = 'header';
      ['#', 'NAME', 'SCORE'].forEach((label) => {
        const th = document.createElement('th');
        th.textContent = label;
        headerRow.appendChild(th);
      });
      table.appendChild(headerRow);

      entries.forEach((entry, index) => {
        const row = document.createElement('tr');
        const rankCell = document.createElement('td');
        rankCell.textContent = String(index + 1);
        const initialsCell = document.createElement('td');
        initialsCell.textContent = entry.initials;
        const scoreCell = document.createElement('td');
        scoreCell.textContent = String(entry.score).padStart(6, '0');
        row.append(rankCell, initialsCell, scoreCell);
        table.appendChild(row);
      });
      wrapper.appendChild(table);
    }

    this.container.appendChild(wrapper);
  }
}
