import * as THREE from 'three';
import { CONFIG } from '../config';
import { makeAABB, type AABB } from '../systems/CollisionSystem';
import { buildInvaderMesh, specForRow, colorFor } from './invaderSprites';

/**
 * A soft radial-gradient texture (opaque white center fading to transparent
 * edges), generated once and shared by every invader's floor marker so the
 * glow reads as a diffuse pool rather than a hard-edged ring.
 */
let softGlowTexture: THREE.Texture | null = null;
function getSoftGlowTexture(): THREE.Texture {
  if (softGlowTexture) return softGlowTexture;
  const size = 128;
  const canvas =
    typeof document !== 'undefined'
      ? document.createElement('canvas')
      : null;
  if (!canvas) {
    // Headless (tests): a 1x1 data texture is enough; visuals aren't asserted.
    softGlowTexture = new THREE.DataTexture(
      new Uint8Array([255, 255, 255, 255]),
      1,
      1,
      THREE.RGBAFormat,
    );
    softGlowTexture.needsUpdate = true;
    return softGlowTexture;
  }
  canvas.width = size;
  canvas.height = size;
  const ctx = canvas.getContext('2d')!;
  const r = size / 2;
  const g = ctx.createRadialGradient(r, r, 0, r, r, r);
  g.addColorStop(0, 'rgba(255,255,255,1)');
  g.addColorStop(0.35, 'rgba(255,255,255,0.55)');
  g.addColorStop(0.7, 'rgba(255,255,255,0.15)');
  g.addColorStop(1, 'rgba(255,255,255,0)');
  ctx.fillStyle = g;
  ctx.fillRect(0, 0, size, size);
  softGlowTexture = new THREE.CanvasTexture(canvas);
  softGlowTexture.needsUpdate = true;
  return softGlowTexture;
}

export class Enemy {
  /** Container object positioned by the grid; holds the voxel invader model. */
  readonly mesh: THREE.Group;
  /** Flat marker on the floor grid showing this invader's X/Z (depth cue). */
  readonly shadow: THREE.Mesh;
  alive = true;
  /** Grid coordinates, used to compute formation position. */
  readonly col: number;
  readonly row: number;
  /** Depth-layer index within a column (0 = front-most, closest to player). */
  readonly layer: number;

  private readonly frames: [THREE.InstancedMesh, THREE.InstancedMesh];
  private frameIndex = 0;
  private readonly shadowMaterial: THREE.MeshBasicMaterial;

  constructor(col: number, row: number, layer = 0) {
    this.col = col;
    this.row = row;
    this.layer = layer;

    // Shape varies by row (5 alien types). Body color varies by BOTH row and
    // depth-layer: rows differ within a layer, and each layer rotates the
    // palette so stacked Z layers are easy to distinguish.
    const palette = colorFor(row, layer);
    const { group, frames } = buildInvaderMesh(specForRow(row), palette);
    this.mesh = group;
    this.frames = frames;

    // A small fuzzy halo around the invader, tinted to its own body color, so
    // each alien reads with a soft colored glow at its borders.
    const haloSize = CONFIG.enemies.size.x * 1.5;
    const haloMaterial = new THREE.SpriteMaterial({
      map: getSoftGlowTexture(),
      color: palette.color,
      transparent: true,
      depthWrite: false,
      blending: THREE.AdditiveBlending,
      opacity: 0.45,
    });
    const halo = new THREE.Sprite(haloMaterial);
    halo.scale.set(haloSize, haloSize, 1);
    this.mesh.add(halo);

    const s = CONFIG.enemies.size;
    // A diffuse glowing pool on the dark floor: a flat plane textured with a
    // soft radial gradient (bright center fading out), additive-blended so it
    // pops against the arena without hard edges.
    const span = s.x * 1.6;
    const shadowGeo = new THREE.PlaneGeometry(span, span);
    shadowGeo.rotateX(-Math.PI / 2); // lay flat on the floor (XZ plane)
    this.shadowMaterial = new THREE.MeshBasicMaterial({
      color: CONFIG.enemies.shadowColor,
      map: getSoftGlowTexture(),
      transparent: true,
      opacity: CONFIG.enemies.shadowOpacityFar,
      depthWrite: false,
      side: THREE.DoubleSide,
      blending: THREE.AdditiveBlending,
    });
    this.shadow = new THREE.Mesh(shadowGeo, this.shadowMaterial);
  }

  /**
   * Places the floor shadow under the invader and adjusts its opacity/scale by
   * depth: closer invaders (lower z) cast a tighter, darker shadow. `t` is the
   * normalized proximity in [0,1] (0 = far/start, 1 = at the player).
   */
  positionShadow(x: number, z: number, floorY: number, t: number): void {
    this.shadow.position.set(x, floorY + 0.02, z);
    const c = CONFIG.enemies;
    this.shadowMaterial.opacity =
      c.shadowOpacityFar + (c.shadowOpacityNear - c.shadowOpacityFar) * t;
    // Grow the marker as the invader approaches so a near fleet reads as a
    // bigger, more urgent glow on the floor.
    const scale = 1 + 0.6 * t;
    this.shadow.scale.set(scale, 1, scale);
  }

  /** Switches to the other animation frame (called once per march step). */
  toggleFrame(): void {
    this.frameIndex ^= 1;
    this.frames[0].visible = this.frameIndex === 0;
    this.frames[1].visible = this.frameIndex === 1;
  }

  kill(): void {
    this.alive = false;
    this.mesh.visible = false;
    this.shadow.visible = false;
  }

  revive(): void {
    this.alive = true;
    this.mesh.visible = true;
    this.shadow.visible = true;
    this.frameIndex = 0;
    this.frames[0].visible = true;
    this.frames[1].visible = false;
  }

  get aabb(): AABB {
    return makeAABB(this.mesh.position, CONFIG.enemies.size);
  }
}
